<div class="d-flex justify-content-between align-items-start gap-3 mb-4"><div><h1 class="h3 mb-1">System upgrade</h1><p class="text-muted mb-0">Apply database migrations in a controlled, recorded sequence.</p></div><span class="badge text-bg-primary fs-6">Version <?=e($version ?: 'unknown')?></span></div>
<div class="row g-3">
 <div class="col-lg-5"><div class="card h-100"><div class="card-body"><h2 class="h5">Pending migrations</h2><?php if($pending):?><ul class="mb-3"><?php foreach($pending as $m):?><li><code><?=e($m)?></code></li><?php endforeach?></ul><form method="post" action="/portal/system/upgrade" onsubmit="return confirm('Apply all pending database migrations?')"><?=csrf_field()?><button class="btn btn-warning"><i class="fa-solid fa-database me-2"></i>Run upgrade</button></form><?php else:?><div class="alert alert-success mb-0"><i class="fa-solid fa-circle-check me-2"></i>The database is current.</div><?php endif?></div></div></div>
 <div class="col-lg-7"><div class="card h-100"><div class="card-header"><strong>Recently applied migrations</strong></div><div class="table-responsive"><table class="table table-sm align-middle mb-0"><thead><tr><th>Migration</th><th>Applied</th><th>Checksum</th></tr></thead><tbody><?php foreach($applied as $row):?><tr><td><code><?=e($row['migration'])?></code></td><td><?=e($row['applied_at'])?></td><td class="small text-muted"><?=e($row['checksum'] ? substr($row['checksum'],0,12).'…' : 'not recorded')?></td></tr><?php endforeach?><?php if(!$applied):?><tr><td colspan="3" class="text-center text-muted py-3">No migration history is available.</td></tr><?php endif?></tbody></table></div></div></div>
</div>
